script.text:

function load$ASPlannedForm(f) {
  f.add_onResponseComplete(on$ASPlannedForm$ResponseComplete);
  if (f._action == 'New') f.setItemValue('ngay_bd', new Date());
}
function scatter$ASPlannedForm(f) {if (f._action == 'New') f.setItemValue('ngay_bd', new Date());}
function close$ASPlannedForm(sender) {try {sender.remove_onResponseComplete(on$ASPlannedForm$ResponseComplete);} catch (ex) {}}
function on$ASPlannedForm$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'MinimumSalary':
      f.setItemValue('luong_tt', result[0].Value);
      onChange$ASPlannedForm$MinimumSalary(f);
      break;
    default:
      break;
  }
}
function onChange$ASPlannedForm$Item(f) {if ((f.getItemValue('ngay_bd')) && (f.getItemValue('ma_nt'))) f.request('MinimumSalary', 'MinimumSalary', ['stt_rec', 'ngay_bd', 'ma_nt']);}
function onChange$ASPlannedForm$MinimumSalary(f) {
  if (f.getItemValue('luong_tt') != 0) {
    onChange$ASPlannedForm$Coefficient(f.getItem('he_so'), 'luong_co_ban');
    for (var i = 1; i <= 3; i++) {
      onChange$ASPlannedForm$Coefficient(f.getItem('hs_phu_cap' + i), 'tien_phu_cap' + i);
    }
  }
}
function onChange$ASPlannedForm$Coefficient(o, c) {
  var f = o.parentForm;
  e = '[' + c + ']:=[' + o.field.Name + ']*[luong_tt]';
  f.executeExpression([e]);
  onChange$ASPlannedForm$Allowance(f);
  f.live(f.getItem(c));
}
function onChange$ASPlannedForm$Allowance(f, o) {
  f.executeExpression(['[t_tien_phu_cap]:=[tien_phu_cap1]+[tien_phu_cap2]+[tien_phu_cap3]']);
  onChange$ASPlannedForm$TotalAllowance(f);
  if (o) {
    if (o.field.Name == 'tien_phu_cap3') f.live(f.getItem('t_tien_phu_cap'));
  }
}
function onChange$ASPlannedForm$TotalAllowance(f) {
  f.executeExpression(['[t_thu_nhap]:=[luong_co_ban]+[t_tien_phu_cap]']);
  f.live(f.getItem('t_thu_nhap'));
}
